import{_ as r,o as s,c as t,a2 as e}from"./chunks/framework.BS3ZfcoS.js";const u=JSON.parse('{"title":"成为喜欢的大人","description":"","frontmatter":{"title":"成为喜欢的大人","author":"","collection":"职场成长","series_order":3,"total_chars":5398},"headers":[],"relativePath":"career/be-adult-you-like.md","filePath":"career/be-adult-you-like.md"}'),o={name:"career/be-adult-you-like.md"};function p(n,a,h,l,i,d){return s(),t("div",null,[...a[0]||(a[0]=[e('<h2 id="s-318" tabindex="-1">成为喜欢的大人 <a class="header-anchor" href="#s-318" aria-label="Permalink to &quot;成为喜欢的大人 {#s-318}&quot;">​</a></h2><p>共24个视频</p><h3 id="s-319" tabindex="-1">20-30岁的男生开窍了有什么变化？（上） <a class="header-anchor" href="#s-319" aria-label="Permalink to &quot;20-30岁的男生开窍了有什么变化？（上） {#s-319}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **开窍是渐进的多维过程，不是突然洗了个大招就变身，更不是变成灭绝师太式的利益动物</p><p>**2. **开窍后的人温和包容、对未知保持坦诚（stay hungry, stay foolish），让万物穿过自己</p><p>**3. **把自己当作解法而非等待别人解决你的问题——造成问题的不是你，但解决问题的人只能是你</p><p><strong>金句</strong></p><p><em>「造成问题的不是你，但是解决问题的人只能是你」</em></p><p><strong>行动指南</strong></p><p>遇到问题先问自己&quot;我能做什么来改变&quot;，而不是归咎他人</p><h3 id="s-320" tabindex="-1">20-30岁的男生开窍了有什么变化？（中） <a class="header-anchor" href="#s-320" aria-label="Permalink to &quot;20-30岁的男生开窍了有什么变化？（中） {#s-320}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **不再以学历论断长短——职场中只看你解决多复杂的问题，CEO就是能解决别人解决不了的问题的人</p><h4 id="s-321" tabindex="-1">2. 不再追逐看起来美好但不属于自己的机会——所有挣钱都是对过去积累的变现 <a class="header-anchor" href="#s-321" aria-label="Permalink to &quot;2. 不再追逐看起来美好但不属于自己的机会——所有挣钱都是对过去积累的变现 {#s-321}&quot;">​</a></h4><h4 id="s-322" tabindex="-1">3. 学会暴露弱点——暴露弱点是构建安全区，让优点也更加明显，形成互补团队 <a class="header-anchor" href="#s-322" aria-label="Permalink to &quot;3. 学会暴露弱点——暴露弱点是构建安全区，让优点也更加明显，形成互补团队 {#s-322}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「所有的挣钱其实都是对你过去积累的变现，如果你没有积累，那再美好的机会其实都不属于你」</em></p><p><strong>行动指南</strong></p><p>坦诚告诉同事你的强项和弱项，主动寻找互补搭档</p><h3 id="s-323" tabindex="-1">20-30岁的男生开窍了有什么变化？（下） <a class="header-anchor" href="#s-323" aria-label="Permalink to &quot;20-30岁的男生开窍了有什么变化？（下） {#s-323}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **意识到自己的独特性才能迸发勇气——爆火的人都是把特质发挥到极致，而非做好所有事</p><h4 id="s-324" tabindex="-1">2. 人生是一场表达，找到独特点并展现出来 <a class="header-anchor" href="#s-324" aria-label="Permalink to &quot;2. 人生是一场表达，找到独特点并展现出来 {#s-324}&quot;">​</a></h4><p>**3. **开窍的本质是&quot;认识你自己&quot;（know yourself）——自我意识的觉醒，不再因外界标准干扰内心判断</p><p><strong>金句</strong></p><p><em>「今日方知我是我」</em></p><p><strong>行动指南</strong></p><p>列出自己最独特的3个特质，思考如何在工作生活中放大它们</p><h3 id="s-325" tabindex="-1">25岁时没人告诉你的事（1-2条） <a class="header-anchor" href="#s-325" aria-label="Permalink to &quot;25岁时没人告诉你的事（1-2条） {#s-325}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **一个月挣的钱只够在ICU住一天——年轻时总以为疾病光顾别人，高压工作的代价是脂肪肝、近视加深、腰椎间盘突出</p><p>**2. **爱情无法免除孤独——不管多爱你的人也不能帮你解决所有问题，爱情不是眼里只有对方，而是各自成长</p><p><strong>金句</strong></p><p><em>「人生本来就是孤独的，爱情也无法免除，你必须要接受这个现实」</em></p><p><strong>行动指南</strong></p><p>每年做一次体检，不要拿身体换KPI</p><h3 id="s-326" tabindex="-1">25岁时没人告诉你的事情（3-5条） <a class="header-anchor" href="#s-326" aria-label="Permalink to &quot;25岁时没人告诉你的事情（3-5条） {#s-326}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-327" tabindex="-1">1. 别人对你的态度取决于你是谁，不是你做了什么——善良要带点锋芒才有价值 <a class="header-anchor" href="#s-327" aria-label="Permalink to &quot;1. 别人对你的态度取决于你是谁，不是你做了什么——善良要带点锋芒才有价值 {#s-327}&quot;">​</a></h4><p>**2. **读书是低效学习方式——知识分显性和隐性，书中多是显性知识，实际问题需要请教高手+实践</p><h4 id="s-328" tabindex="-1">3. 只有失败+反思=成长，不加反思的失败只会带来失败 <a class="header-anchor" href="#s-328" aria-label="Permalink to &quot;3. 只有失败+反思=成长，不加反思的失败只会带来失败 {#s-328}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「别人对你的态度不取决于你做什么，而取决于你是谁」</em></p><p><strong>行动指南</strong></p><p>每次失败后写反思笔记——为什么失败？暴露了什么弱点？下次如何改进？</p><h3 id="s-329" tabindex="-1">25岁时没人告诉你的事情（6-8条） <a class="header-anchor" href="#s-329" aria-label="Permalink to &quot;25岁时没人告诉你的事情（6-8条） {#s-329}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-330" tabindex="-1">1. 原生家庭决定论是因果论的自我束缚——成年人要对自己负责，做自己的父母 <a class="header-anchor" href="#s-330" aria-label="Permalink to &quot;1. 原生家庭决定论是因果论的自我束缚——成年人要对自己负责，做自己的父母 {#s-330}&quot;">​</a></h4><p>**2. **比起匆匆定目标，更重要的是了解自己——不了解自己也不了解世界时制定的目标大多是假目标</p><h4 id="s-331" tabindex="-1">3. 每个人都有自己的时区和步调——不要用年龄数字框死自己 <a class="header-anchor" href="#s-331" aria-label="Permalink to &quot;3. 每个人都有自己的时区和步调——不要用年龄数字框死自己 {#s-331}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「纽约的时间比加州时间早三个小时，但加州并没有变慢」</em></p><p><strong>行动指南</strong></p><p>停止拿自己的进度和别人比较，列一份&quot;我真正想要什么&quot;的清单</p><h3 id="s-332" tabindex="-1">被富养vs穷养长大的女生（富养篇） <a class="header-anchor" href="#s-332" aria-label="Permalink to &quot;被富养vs穷养长大的女生（富养篇） {#s-332}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **富养的核心不是钱多，而是环境带来的认知优势和精英视野——小学同学00年代初就立志去哈佛</p><p>**2. **真正的富人培养孩子的方式：16岁给钱开咖啡厅学运营、带去跟券商律所交流学谈判、周末家庭读书会</p><p>**3. **物质优渥不一定带来更多快乐——满足一定物质条件后，快乐阈值就到了，真正的快乐来自持续做热爱的事</p><p><strong>金句</strong></p><p><em>「一个人不能赚到他认知范围之外的钱」</em></p><p><strong>行动指南</strong></p><p>主动接触比自己优秀的环境和人，用信息差和认知升级替代单纯消费</p><h3 id="s-333" tabindex="-1">被富养vs穷养长大的女生（穷养篇） <a class="header-anchor" href="#s-333" aria-label="Permalink to &quot;被富养vs穷养长大的女生（穷养篇） {#s-333}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **穷养孩子的思维模式：听到任何事第一反应是&quot;需要花多少钱&quot;，物质成为做事情的第一个卡点</p><p>**2. **切换视角看穷养——不要从过去找缺陷，要从过去找力量：匮乏让我学会读书、学会与伟大灵魂对话</p><p>**3. **适度匮乏反而培养对物质的尊重和持续获得快乐的能力——富足的人往往不能从物质中得到快乐</p><p><strong>金句</strong></p><p><em>「不要从过去找缺陷，而要从过去找力量」</em></p><p><strong>行动指南</strong></p><p>回顾你的匮乏经历，写下它赋予你的3个正面能力</p><h3 id="s-334" tabindex="-1">双非二本、考研失败、零实习我如何混进大厂？一个普通女孩的十年 <a class="header-anchor" href="#s-334" aria-label="Permalink to &quot;双非二本、考研失败、零实习我如何混进大厂？一个普通女孩的十年 {#s-334}&quot;">​</a></h3><p>**备注：**<em>ASR内容为歌曲歌词重复，无实质可萃取内容，跳过</em></p><h3 id="s-335" tabindex="-1">迷茫焦虑时看的3本绝世好书——《毛选》 <a class="header-anchor" href="#s-335" aria-label="Permalink to &quot;迷茫焦虑时看的3本绝世好书——《毛选》 {#s-335}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **你的成长就是对自己的革命——不是花拳绣腿的自我感动，是要亲自下场解决问题、承受痛击</p><h4 id="s-336" tabindex="-1">2. 实践调查比空想重要——不做调查而苦思冥想的人一定想不出好办法 <a class="header-anchor" href="#s-336" aria-label="Permalink to &quot;2. 实践调查比空想重要——不做调查而苦思冥想的人一定想不出好办法 {#s-336}&quot;">​</a></h4><h4 id="s-337" tabindex="-1">3. 从人民群众中来到人民群众中去——做任何事都要了解真实需求，而不是自嗨 <a class="header-anchor" href="#s-337" aria-label="Permalink to &quot;3. 从人民群众中来到人民群众中去——做任何事都要了解真实需求，而不是自嗨 {#s-337}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「革命不是请客吃饭，不是做文章，不是绘画绣花，不能那样雅致，那样从容不迫，文质彬彬」</em></p><p><strong>行动指南</strong></p><p>遇到问题先去做调查和实操，而非闭门苦想</p><h3 id="s-338" tabindex="-1">迷茫焦虑时看的3本绝世好书——《遥远的救世主》 <a class="header-anchor" href="#s-338" aria-label="Permalink to &quot;迷茫焦虑时看的3本绝世好书——《遥远的救世主》 {#s-338}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **文化属性分强势文化和弱势文化——强势文化尊重客观规律，弱势文化依赖他人等待救世主</p><p>**2. **传统文化的深层逻辑是皇恩浩荡——人人都盼望更强大的他人来拯救自己，从未把目光放在自己身上</p><p>**3. **所谓的救世主根本不存在——每个人只能自己拯救自己，你的命运是你内心文化的产物</p><p><strong>金句</strong></p><p><em>「所谓的救世主其实是根本不存在的，我们每一个人只能自己拯救自己」</em></p><p><strong>行动指南</strong></p><p>觉察你内心的文化属性——你是在等救世主，还是在挖掘自己的力量？</p><h3 id="s-339" tabindex="-1">迷茫焦虑时看的3本绝世好书——《中国哲学简史》 <a class="header-anchor" href="#s-339" aria-label="Permalink to &quot;迷茫焦虑时看的3本绝世好书——《中国哲学简史》 {#s-339}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **尽人事听天命——外部条件是否配合非人力可控，人所有能做的是竭尽全力，对结果在所不惜</p><p>**2. **文化母题概念——你的精神面貌被所处文化塑造，了解它才能知道自己如何被塑造、将走向何处</p><h4 id="s-340" tabindex="-1">3. 一个人精神弱小无所依托，是因为对世界没有形成系统而稳定的看法 <a class="header-anchor" href="#s-340" aria-label="Permalink to &quot;3. 一个人精神弱小无所依托，是因为对世界没有形成系统而稳定的看法 {#s-340}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「君子坦荡荡，小人长戚戚」</em></p><p><strong>行动指南</strong></p><p>了解你的文化母题——读一本中国哲学入门书，反思哪些观念在塑造你</p><h3 id="s-341" tabindex="-1">女生必看的3部纪录片（上）——《女人》《生门》 <a class="header-anchor" href="#s-341" aria-label="Permalink to &quot;女生必看的3部纪录片（上）——《女人》《生门》 {#s-341}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **《女人》：50国2000名女性独白，不为女性处境只讲痛苦，也为身为女性的骄傲和美</p><p>**2. **《生门》：生育中的真实生死抉择——大出血时子宫和性命只能选一个，女人经济独立太重要了</p><h4 id="s-342" tabindex="-1">3. 面对恐惧不应避而不谈，而应直面了解真实场景 <a class="header-anchor" href="#s-342" aria-label="Permalink to &quot;3. 面对恐惧不应避而不谈，而应直面了解真实场景 {#s-342}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「女人经济独立真的太重要了，不然在这种生死关头你的命都不在你手里」</em></p><p><strong>行动指南</strong></p><p>不回避令你恐惧的真相，主动了解再做决策</p><h3 id="s-343" tabindex="-1">女生必看的3部纪录片（下）——《女大法官金斯伯格》 <a class="header-anchor" href="#s-343" aria-label="Permalink to &quot;女生必看的3部纪录片（下）——《女大法官金斯伯格》 {#s-343}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-344" tabindex="-1">1. 做淑女也独立自主——不被无用情绪绑架，但也必须学会独立生活 <a class="header-anchor" href="#s-344" aria-label="Permalink to &quot;1. 做淑女也独立自主——不被无用情绪绑架，但也必须学会独立生活 {#s-344}&quot;">​</a></h4><h4 id="s-345" tabindex="-1">2. 不要用年龄、性别、出身标签定义自己，而是用你做的事情来定义自己 <a class="header-anchor" href="#s-345" aria-label="Permalink to &quot;2. 不要用年龄、性别、出身标签定义自己，而是用你做的事情来定义自己 {#s-345}&quot;">​</a></h4><h4 id="s-346" tabindex="-1">3. 即使遇到白马王子也是福气，但你必须懂得独立生活 <a class="header-anchor" href="#s-346" aria-label="Permalink to &quot;3. 即使遇到白马王子也是福气，但你必须懂得独立生活 {#s-346}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「不要用年龄、性别、出身这些标签来定义你，而是要用你做的事情来定义自己」</em></p><p><strong>行动指南</strong></p><p>写下你希望自己被定义的3件事，用行动而非标签证明自己</p><h3 id="s-347" tabindex="-1">27岁，大厂裸辞不上班的一年 <a class="header-anchor" href="#s-347" aria-label="Permalink to &quot;27岁，大厂裸辞不上班的一年 {#s-347}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **真正卡住你的往往不是客观准备（钱和资源），而是主观准备（勇气）——够两年生活费还不敢辞职</p><p>**2. **自由市场比职场更残酷——企业某种程度上也在保护我们的平庸，独自面对市场你就是唯一生产力</p><h4 id="s-348" tabindex="-1">3. 进入新世界要放下旧规则的执念（OKR、KPI），新世界玩法不一样 <a class="header-anchor" href="#s-348" aria-label="Permalink to &quot;3. 进入新世界要放下旧规则的执念（OKR、KPI），新世界玩法不一样 {#s-348}&quot;">​</a></h4><h4 id="s-349" tabindex="-1">4. 不能照顾好自己就无法好好工作——先睡好、休息好，才能创造 <a class="header-anchor" href="#s-349" aria-label="Permalink to &quot;4. 不能照顾好自己就无法好好工作——先睡好、休息好，才能创造 {#s-349}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「真正卡住你的是主观的准备，比如勇气」</em></p><p><strong>行动指南</strong></p><p>列出你一直想做但不敢做的事，评估阻碍是客观条件还是主观恐惧</p><h3 id="s-350" tabindex="-1">女生开窍后的7个改变（1-2条） <a class="header-anchor" href="#s-350" aria-label="Permalink to &quot;女生开窍后的7个改变（1-2条） {#s-350}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **从顺从者走向自立者——女性从小被鼓励依赖别人而非靠自己，开窍的关键是找到属于自己的路并坚定不移</p><p>**2. **不再耿耿于怀原生家庭——找力量而非找缺陷，做自己的父母，痛苦不是力量之源，解决了痛苦才是</p><p><strong>金句</strong></p><p><em>「痛苦其实不是力量之源，只有你解决了痛苦，它才能够成为你的力量之一」</em></p><p><strong>行动指南</strong></p><p>当你想起原生家庭的伤害时，刻意寻找那段经历赋予你的力量</p><h3 id="s-351" tabindex="-1">女生开窍后的7个改变（3-5条） <a class="header-anchor" href="#s-351" aria-label="Permalink to &quot;女生开窍后的7个改变（3-5条） {#s-351}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-352" tabindex="-1">1. 面对公司上级要不卑不亢有配得感——你不是为老板打工，是为自己的简历打工 <a class="header-anchor" href="#s-352" aria-label="Permalink to &quot;1. 面对公司上级要不卑不亢有配得感——你不是为老板打工，是为自己的简历打工 {#s-352}&quot;">​</a></h4><p>**2. **不再纠结人际关系——你能帮助的人才是你的人脉；好的关系是两个善良正直的人自动产生，不用经营</p><p>**3. **不再想着改变别人，学会顺应人心做事——强者制定规则，弱者遵守规则，智者利用规则</p><p><strong>金句</strong></p><p><em>「你能帮助的人才是真正的人脉，如果你不能给别人提供帮助，他们就跟你毫无关系」</em></p><p><strong>行动指南</strong></p><p>人际关系的精力分配从&quot;讨好每个人&quot;转向&quot;筛选值得深交的人&quot;</p><h3 id="s-353" tabindex="-1">女生开窍后的7个改变（6-7条） <a class="header-anchor" href="#s-353" aria-label="Permalink to &quot;女生开窍后的7个改变（6-7条） {#s-353}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **正视金钱——钱是能力的外显，没有财务自由就不要谈精神自由，银行卡余额就是精神自由的程度</p><p>**2. **照顾好自己是第一要务——长期压抑自己需求去满足别人，最终连满足别人的需求都做不好</p><p>**3. **开窍不能强求外力、也不必跟别人一样——庄子混沌开窍的故事：每天凿一窍，第七天混沌就死了</p><p><strong>金句</strong></p><p><em>「没有财务自由，就不要去谈精神自由，你银行卡里的余额就是你精神自由的程度」</em></p><p><strong>行动指南</strong></p><p>今天立刻去做一件你一直想做但拖延的小事，先让自己&quot;小小的得偿所愿&quot;</p><h3 id="s-354" tabindex="-1">25岁没人告诉你，趁早知道的8个人生真相·职场篇（第1条） <a class="header-anchor" href="#s-354" aria-label="Permalink to &quot;25岁没人告诉你，趁早知道的8个人生真相·职场篇（第1条） {#s-354}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **真正的天赋不在于什么让你爽，而在于什么让你不爽——你的不能忍往往就是你的天赋所在</p><h4 id="s-355" tabindex="-1">2. 因为不做就受不了，所以会做很久；做足够久，就一定能做好 <a class="header-anchor" href="#s-355" aria-label="Permalink to &quot;2. 因为不做就受不了，所以会做很久；做足够久，就一定能做好 {#s-355}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「你的不能忍，往往就是你的天赋所在，因为你不做他就受不了」</em></p><p><strong>行动指南</strong></p><p>反问自己——什么事情让你无法忍受、不做就难受？那可能就是你的天赋方向</p><h3 id="s-356" tabindex="-1">25岁没人告诉你，趁早知道的8个人生真相·职场篇（第2条） <a class="header-anchor" href="#s-356" aria-label="Permalink to &quot;25岁没人告诉你，趁早知道的8个人生真相·职场篇（第2条） {#s-356}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **对普通人而言，勇气是最大的资产——像站在熔炉旁的钢板，必须纵深一跃才能成为好钢板</p><h4 id="s-357" tabindex="-1">2. 缺少金钱学历出身只是开局难一点，缺少勇气才是真的一无所有 <a class="header-anchor" href="#s-357" aria-label="Permalink to &quot;2. 缺少金钱学历出身只是开局难一点，缺少勇气才是真的一无所有 {#s-357}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「缺少金钱学历出身，你只是开局稍微难了一点，但缺少勇气，你是真的一无所有了」</em></p><p><strong>行动指南</strong></p><p>下次面对机会犹豫时，问自己——最坏的结果是什么？我能承受吗？</p><h3 id="s-358" tabindex="-1">25岁没人告诉你，趁早知道的8个人生真相·职场篇（第3-4条） <a class="header-anchor" href="#s-358" aria-label="Permalink to &quot;25岁没人告诉你，趁早知道的8个人生真相·职场篇（第3-4条） {#s-358}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **经营自己比经营同事关系重要——被人尊重比被人喜欢更重要；你认识多少人不是人脉，你能帮助的才是</p><p>**2. **真正的成就来自一个点挖足够深——FOMO让人挖无数浅坑，但成就在于把1米宽的坑挖万米深</p><p>**3. **养成复盘习惯，把碎片化思考系统化——每解决一个反复出现的问题就建总文档，搭建自己的武功秘籍</p><p><strong>金句</strong></p><p><em>「你认识多少人并不是你的人脉，你能帮助的那些人才是你的人脉」</em></p><p><strong>行动指南</strong></p><p>每次完成重要任务后立即复盘，重复出现3次以上的问题建立专属解决文档</p><h3 id="s-359" tabindex="-1">25岁没人告诉你，趁早知道的8个人生真相·职场篇（第5-7条） <a class="header-anchor" href="#s-359" aria-label="Permalink to &quot;25岁没人告诉你，趁早知道的8个人生真相·职场篇（第5-7条） {#s-359}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **配得感——缺少配得感会把自己放在任人审判的位置，你要相信自己值得平等的对待</p><p>**2. **成功≠成长——成长是人格丰富性的完善，是从失败中进化出来的能力，过程沉淀的能力才是真正附着在你身上的</p><h4 id="s-360" tabindex="-1">3. 职业规划不是岗位跃迁，而是可迁移能力的升级打怪——岗位会消失，但能力不会 <a class="header-anchor" href="#s-360" aria-label="Permalink to &quot;3. 职业规划不是岗位跃迁，而是可迁移能力的升级打怪——岗位会消失，但能力不会 {#s-360}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「真正的职业规划不是以岗位为主体的跃迁，而是以能力为主体的升级打怪」</em></p><p><strong>行动指南</strong></p><p>定义你的核心可迁移能力——当行业颠覆时你还能靠什么吃饭？</p><h3 id="s-361" tabindex="-1">25岁没人告诉你，趁早知道的8个人生真相·职场篇（第8条） <a class="header-anchor" href="#s-361" aria-label="Permalink to &quot;25岁没人告诉你，趁早知道的8个人生真相·职场篇（第8条） {#s-361}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **幸福在于多满足内部需求、少迎合外部需求——追逐外部认可时，自己的声音在慢慢消失</p><p>**2. **用自己的价值筹码（DB）给事情定价值——常规日会200DB，约会看电影600DB，创造好内容1000DB</p><h4 id="s-362" tabindex="-1">3. 工作也是很多人生问题的解法——什么拯救过你，就拿它来拯救世界 <a class="header-anchor" href="#s-362" aria-label="Permalink to &quot;3. 工作也是很多人生问题的解法——什么拯救过你，就拿它来拯救世界 {#s-362}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「什么拯救过你，就拿它来拯救世界」</em></p><p><strong>行动指南</strong></p><p>给自己的日常事务赋价值分，把时间花在分值最高的事上</p><h3 id="s-363" tabindex="-1">28岁发现：原来裸辞和旅行并不会让你感到快乐 <a class="header-anchor" href="#s-363" aria-label="Permalink to &quot;28岁发现：原来裸辞和旅行并不会让你感到快乐 {#s-363}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **&quot;生活在别处&quot;是幻觉——一旦别处变成此处，人就会迅速感到乏味，新鲜感消退极快</p><p>**2. **变老就是越来越理性，理性是一种防御，阻止了感受——你不再犯错，但也不再着迷</p><h4 id="s-364" tabindex="-1">3. 工作训练让你倾向于用经济和文化模型理解新环境，陌生也会迅速变可预测、重复 <a class="header-anchor" href="#s-364" aria-label="Permalink to &quot;3. 工作训练让你倾向于用经济和文化模型理解新环境，陌生也会迅速变可预测、重复 {#s-364}&quot;">​</a></h4><p>**4. **快乐不来自外部情境变化，而来自内心与真实自我的连接——意义不在远方，而在此刻真实的感受中</p><p><strong>金句</strong></p><p><em>「一个人变老就是越来越理性，理性是一种防御，防御阻止你的感受，于是你不再犯错，但也不再着迷」</em></p><p><strong>行动指南</strong></p><p>每天做一件不功利、纯粹感受的事情，抵抗理性对感受的防御</p>',209)])])}const c=r(o,[["render",p]]);export{u as __pageData,c as default};
